{
  "sentences": [
    {
      "text": "我學中文的目標是為了將來在台灣工作。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì wèile jiānglái zài Táiwān gōngzuò.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 wei4le0 jiang1lai2 zai4 Tai2wan1 gong1zuo4.",
      "translation_en": "My goal in learning Chinese is to work in Taiwan in the future.",
      "translation_ko": "제가 중국어를 배우는 목표는 장래에 대만에서 일하기 위해서입니다."
    },
    {
      "text": "我從美國來，現在在台北學中文。",
      "pinyin": "Wǒ cóng Měiguó lái, xiànzài zài Táiběi xué Zhōngwén.",
      "pinyin_numeric": "wo3 cong2 Mei3guo2 lai2, xian4zai4 zai4 Tai2bei3 xue2 Zhong1wen2.",
      "translation_en": "I come from the United States, and now I'm studying Chinese in Taipei.",
      "translation_ko": "저는 미국에서 왔고, 지금 타이베이에서 중국어를 배우고 있습니다."
    },
    {
      "text": "我學中文的目標是希望通過考試。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì xīwàng tōngguò kǎoshì.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 xi1wang4 tong1guo4 kao3shi4.",
      "translation_en": "My goal in learning Chinese is to hope to pass the exam.",
      "translation_ko": "제가 중국어를 배우는 목표는 시험에 합격하기를 바라는 것입니다."
    },
    {
      "text": "我是一個工程師，學中文是為了工作。",
      "pinyin": "Wǒ shì yī ge gōngchéngshī, xué Zhōngwén shì wèile gōngzuò.",
      "pinyin_numeric": "wo3 shi4 yi1 ge0 gong1cheng2shi1, xue2 Zhong1wen2 shi4 wei4le0 gong1zuo4.",
      "translation_en": "I am an engineer, and I study Chinese for work.",
      "translation_ko": "저는 엔지니어이고, 일 때문에 중국어를 배웁니다."
    },
    {
      "text": "我學中文的目標是說得很流利。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì shuō de hěn liúlì.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 shuo1 de0 hen3 liu2li4.",
      "translation_en": "My goal in learning Chinese is to speak it very fluently.",
      "translation_ko": "제가 중국어를 배우는 목표는 유창하게 말하는 것입니다."
    },
    {
      "text": "我從日本來，在台灣留學，學中文。",
      "pinyin": "Wǒ cóng Rìběn lái, zài Táiwān liúxué, xué Zhōngwén.",
      "pinyin_numeric": "wo3 cong2 Ri4ben3 lai2, zai4 Tai2wan1 liu2xue2, xue2 Zhong1wen2.",
      "translation_en": "I come from Japan, I'm studying abroad in Taiwan, learning Chinese.",
      "translation_ko": "저는 일본에서 왔고, 대만에서 유학하며 중국어를 배웁니다."
    },
    {
      "text": "我學中文的目標是為了了解台灣文化。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì wèile liǎojiě Táiwān wénhuà.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 wei4le0 liao3jie3 Tai2wan1 wen2hua4.",
      "translation_en": "My goal in learning Chinese is to understand Taiwanese culture.",
      "translation_ko": "제가 중국어를 배우는 목표는 대만 문화를 이해하기 위해서입니다."
    },
    {
      "text": "我是一個學生，學中文已經兩年了。",
      "pinyin": "Wǒ shì yī ge xuéshēng, xué Zhōngwén yǐjīng liǎng nián le.",
      "pinyin_numeric": "wo3 shi4 yi1 ge0 xue2sheng1, xue2 Zhong1wen2 yi3jing1 liang3 nian2 le0.",
      "translation_en": "I am a student, and I have been learning Chinese for two years.",
      "translation_ko": "저는 학생이고, 중국어를 배운 지 벌써 2년이 되었습니다."
    },
    {
      "text": "我學中文的目標是將來當醫生。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì jiānglái dāng yīshēng.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 jiang1lai2 dang1 yi1sheng1.",
      "translation_en": "My goal in learning Chinese is to become a doctor in the future.",
      "translation_ko": "제가 중국어를 배우는 목표는 장래에 의사가 되는 것입니다."
    },
    {
      "text": "我學中文的目標是希望進步很快。",
      "pinyin": "Wǒ xué Zhōngwén de mùbiāo shì xīwàng jìnbù hěn kuài.",
      "pinyin_numeric": "wo3 xue2 Zhong1wen2 de0 mu4biao1 shi4 xi1wang4 jin4bu4 hen3 kuai4.",
      "translation_en": "My goal in learning Chinese is to hope to improve quickly.",
      "translation_ko": "제가 중국어를 배우는 목표는 빨리 발전하기를 바라는 것입니다."
    }
  ]
}
